#include<bits/stdc++.h>
using namespace std;
int main() {
	int n, k, b, d;
	cin >> n;
	if(n==1){
	    cout<<1;
	    return 0;
	}
	int a[n][n];
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			a[i][j] = 0;
		}
	}
	a[0][n / 2 ] = 1;
	b = 0;
	d = n / 2 ;
	k = 2;
	while (k != (n * n)) {
		if (b == 0 && d != n-1) {
			a[n-1][d+1] = k;
			d++;
			b =n-1;
			k++;
		}
		if (d == n-1 && b != 0) {
			a[b-1][0] = k;
			b--;
			d = 0;
			k++;
		}
		if (b == 0 && d == n-1) {
			a[b + 1][d] = k;
			b++;
			k++;
		}
		if (d != n-1 && b != 0) {
			if (a[b - 1][d + 1] == 0) {
				a[b - 1][d + 1] = k;
				b--;
				d++;
			
			} else {
				a[b + 1][d] = k;
				b++;
			
			}k++;
		}
		
	}a[n-1][n /2]=n*n;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			cout << a[i][j] << " ";
		}
		cout << endl;
	}return 0;
}
